tools.description:
Deploys an Edge Function to a Supabase project. If the function already exists, this will create a new version. Example:

import "jsr:@supabase/functions-js/edge-runtime.d.ts";

Deno.serve(async (req: Request) => {
  const data = {
    message: "Hello there!"
  };

  return new Response(JSON.stringify(data), {
    headers: {
      'Content-Type': 'application/json',
      'Connection': 'keep-alive'
    }
  });
});

output.arguments:
{"query":"select count(*) as part_count
from (
  select p.p_partkey
  from public.customer c
  join public."order" o on o.o_custkey = c.c_custkey
  join public.lineitem l on l.l_orderkey = o.o_orderkey
  join public.part p on p.p_partkey = l.l_partkey
  where c.c_mktsegment = 'BUILDING'
  group by p.p_partkey
) t;"}
